import{_ as a,o as e,c as r,a2 as o}from"./chunks/framework.Crpw6aS5.js";const q=JSON.parse('{"title":"埃坦·韦特海默","description":"","frontmatter":{"title":"埃坦·韦特海默"},"headers":[],"relativePath":"04_people/埃坦·韦特海默.md","filePath":"04_people/埃坦·韦特海默.md"}'),l={name:"04_people/埃坦·韦特海默.md"};function h(i,t,d,n,u,s){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="埃坦·韦特海默-eitan-wertheimer" tabindex="-1">埃坦·韦特海默（Eitan Wertheimer） <a class="header-anchor" href="#埃坦·韦特海默-eitan-wertheimer" aria-label="Permalink to &quot;埃坦·韦特海默（Eitan Wertheimer）&quot;">​</a></h1><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>姓名</strong></td><td>Eitan Wertheimer（埃坦·韦特海默）</td></tr><tr><td><strong>职位</strong></td><td>ISCAR董事长</td></tr><tr><td><strong>关联公司</strong></td><td>ISCAR（伊斯卡金属切削集团）</td></tr><tr><td><strong>首次提及</strong></td><td>2006年</td></tr></tbody></table><h2 id="与巴菲特的故事" tabindex="-1">与巴菲特的故事 <a class="header-anchor" href="#与巴菲特的故事" aria-label="Permalink to &quot;与巴菲特的故事&quot;">​</a></h2><p>埃坦·韦特海默是ISCAR的董事长，他主动写信给巴菲特促成了这笔40亿美元的交易，被誉为&quot;一封改变命运的信&quot;。</p><h3 id="一封信促成的收购" tabindex="-1">一封信促成的收购 <a class="header-anchor" href="#一封信促成的收购" aria-label="Permalink to &quot;一封信促成的收购&quot;">​</a></h3><p>2005年10月25日，巴菲特收到了一封来自陌生人的信：</p><blockquote><p>&quot;埃坦的一封一又四分之一页的信，那时我对他一无所知。信的开头写道：我写信是为了向您介绍ISCAR，然后描述了一家在61个国家开展业务的切削工具业务。接着埃坦写道：我们有一段时间考虑了大家族企业典型的代际传承和所有权问题，并对ISCAR的未来进行了深思熟虑。我们的结论是，伯克希尔·哈撒韦将是ISCAR的理想归宿。&quot;（2006年股东信）</p></blockquote><blockquote><p>&quot;总的来说，埃坦的信让公司的质量和管理层的品格跃然纸上。&quot;（2006年股东信）</p></blockquote><h3 id="以色列之行" tabindex="-1">以色列之行 <a class="header-anchor" href="#以色列之行" aria-label="Permalink to &quot;以色列之行&quot;">​</a></h3><p>巴菲特亲自前往以色列考察ISCAR，留下了深刻印象：</p><blockquote><p>&quot;9月，查理和我以及其他五位伯克希尔同事访问了以色列的ISCAR。我们——我是说我们每一个人——从未对任何一家企业如此印象深刻。在ISCAR，如同在整个以色列，智慧和活力无处不在。&quot;（2006年股东信）</p></blockquote><h3 id="持续卓越" tabindex="-1">持续卓越 <a class="header-anchor" href="#持续卓越" aria-label="Permalink to &quot;持续卓越&quot;">​</a></h3><p>ISCAR被收购后持续创造出色业绩，巴菲特多次赞誉韦特海默和他的管理团队：</p><blockquote><p>&quot;Iscar的经理——Eitan Wertheimer、Jacob Harpaz、Danny Goldman——是杰出的战略家和运营商。&quot;（2011年股东信）</p></blockquote><blockquote><p>&quot;收购一家公司能 secured 这样三位经理人，真就像赢了三冠王。Iscar自从我们收购后增长超过我们预期。&quot;（2008年股东信）</p></blockquote><h3 id="家族合伙人" tabindex="-1">家族合伙人 <a class="header-anchor" href="#家族合伙人" aria-label="Permalink to &quot;家族合伙人&quot;">​</a></h3><p>伯克希尔以40亿美元收购了ISCAR 80%的股份，剩余20%由韦特海默家族持有，巴菲特特别强调他们是&quot;重要的合作伙伴&quot;。</p><h2 id="关联年份" tabindex="-1">关联年份 <a class="header-anchor" href="#关联年份" aria-label="Permalink to &quot;关联年份&quot;">​</a></h2><p>2005, 2006, 2007, 2008, 2010, 2011</p><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li><a href="./../03_公司库/ISCAR.html">ISCAR</a> - 管理的公司</li><li><a href="./雅各布·哈帕兹.html">雅各布·哈帕兹</a> - CEO搭档</li><li><a href="./../03_公司库/伯克希尔哈撒韦.html">伯克希尔·哈撒韦</a> - 母公司</li></ul><hr><p><em>最后更新：2026-04-09</em></p><h2 id="相关信件" tabindex="-1">相关信件 <a class="header-anchor" href="#相关信件" aria-label="Permalink to &quot;相关信件&quot;">​</a></h2><ul><li><a href="./../01_letters/2006年/翻译.html">2006年</a></li><li><a href="./../01_letters/2009年/翻译.html">2009年</a></li></ul>',26)])])}const p=a(l,[["render",h]]);export{q as __pageData,p as default};
